const PAGE_DATA=window.APP_CONTENT||{};const heroBackdrop=document.getElementById("heroBackdrop");const heroBackdropBlur=document.getElementById("heroBackdropBlur");const contactsBackdrop=document.getElementById("contactsBackdrop");const socialsBackdrop=document.getElementById("socialsBackdrop");const foundersList=document.getElementById("foundersList");const commonEmail=document.getElementById("commonEmail");const commonAddress=document.getElementById("commonAddress");const legalCompany=document.getElementById("legalCompany");const legalInn=document.getElementById("legalInn");const socialsList=document.getElementById("socialsList");const copyToast=document.getElementById("copyToast");const openContactsButton=document.getElementById("openContacts");const openSocialsButton=document.getElementById("openSocials");function preloadImage(url){if(!url)return;const l=document.createElement("link");l.rel="preload";l.as="image";l.href=url;document.head.appendChild(l);}function preloadImages(urls){(urls||[]).forEach((u)=>preloadImage(u));}function ensureImageLoaded(imgEl,url){if(!imgEl||!url)return;if(imgEl.getAttribute("src"))return;imgEl.src=url;imgEl.addEventListener("load",()=>{imgEl.classList.add("loaded");},{once:true},);}function applyTextLabels(){const labels=PAGE_DATA.labels||{};if(openContactsButton&&labels.contactsButton)openContactsButton.textContent=labels.contactsButton;if(openSocialsButton&&labels.socialsButton)openSocialsButton.textContent=labels.socialsButton;const hint=document.getElementById("hintTapToOpen");if(hint&&labels.hintTapToOpen)hint.textContent=labels.hintTapToOpen;const contactsTitle=document.getElementById("contactsModalTitle");if(contactsTitle&&labels.contactsModalTitle)contactsTitle.textContent=labels.contactsModalTitle;const socialsTitle=document.getElementById("socialsModalTitle");if(socialsTitle&&labels.socialsModalTitle)socialsTitle.textContent=labels.socialsModalTitle;const foundersTitle=document.getElementById("foundersTitle");if(foundersTitle&&labels.foundersTitle)foundersTitle.textContent=labels.foundersTitle;const commonTitle=document.getElementById("commonContactsTitle");if(commonTitle&&labels.commonContactsTitle)commonTitle.textContent=labels.commonContactsTitle;}function setResponsiveProfile(){const w=window.innerWidth;const h=window.innerHeight;document.body.classList.remove("profile-phone-small","profile-phone-regular","profile-tablet","profile-desktop");if(w>=1024)document.body.classList.add("profile-desktop");else if(w>=768)document.body.classList.add("profile-tablet");else if(h<=680)document.body.classList.add("profile-phone-small");else document.body.classList.add("profile-phone-regular");}function updateHeroOverlayContrast(){const isSmall=document.body.classList.contains("profile-phone-small");const isDesktop=document.body.classList.contains("profile-desktop");const top=isSmall?0.2:0.14;const mid=isSmall?0.1:0.06;const bottom=isDesktop?0.66:0.72;document.documentElement.style.setProperty("--hero-top",String(top));document.documentElement.style.setProperty("--hero-mid",String(mid));document.documentElement.style.setProperty("--hero-bottom",String(bottom));}function iconImage(src,alt){return `<img src="${src}" alt="${alt}" class="h-7 w-7 object-contain"/>`;}function socialIconImage(src,alt){return `<img src="${src}" alt="${alt}" class="social-icon-strong"/>`;}function brandLogoInline(){const src=PAGE_DATA.images.brandLogo;if(!src)return '<span class="social-text-strong">ТД СХР</span>';return `<span class="brand-mark-wrap"><img src="${src}" alt="ТД СХР" class="brand-mark"/></span>`;}function isPlaceholder(href){return!href||href.trim()==="#"||href.trim().toLowerCase()==="javascript:void(0)";}async function copyToClipboard(text){if(!text)return false;try{await navigator.clipboard.writeText(text);return true;}catch{const area=document.createElement("textarea");area.value=text;area.style.position="fixed";area.style.opacity="0";document.body.appendChild(area);area.focus();area.select();const ok=document.execCommand("copy");document.body.removeChild(area);return ok;}}let toastTimer;function showCopyToast(message){if(!copyToast)return;copyToast.textContent=message||PAGE_DATA.labels?.copied||"Скопировано";copyToast.classList.add("show");clearTimeout(toastTimer);toastTimer=setTimeout(()=>copyToast.classList.remove("show"),1000);}function bindLongPressCopy(element,getValue){if(!element)return;let pressTimer=null;let isTriggered=false;const start=()=>{isTriggered=false;clearTimeout(pressTimer);pressTimer=setTimeout(async()=>{isTriggered=true;const value=typeof getValue==="function"?getValue():"";const copied=await copyToClipboard(value);if(copied)showCopyToast();},450);};const cancel=()=>clearTimeout(pressTimer);element.addEventListener("touchstart",start,{passive:true});element.addEventListener("mousedown",start);["touchend","touchcancel","mouseup","mouseleave"].forEach((evt)=>element.addEventListener(evt,cancel));element.addEventListener("click",(event)=>{if(isTriggered){event.preventDefault();event.stopPropagation();}});}function founderContactButton(iconSrc,label,href){const disabled=isPlaceholder(href);return `<a href="${disabled?"#":href}" target="_blank" rel="noreferrer" class="tap flex h-11 items-center justify-center gap-2 rounded-xl border border-white/20 bg-black/45 px-3 text-sm text-slate-100 ${disabled?"disabled-link":""}">${iconImage(iconSrc,label)}<span>${label}</span></a>`;}function founderAvatar(person){if(person.avatar)return `<img src="${person.avatar}" alt="${person.fullName}" class="founder-avatar"/>`;const initials=person.fullName.split(" ").filter(Boolean).slice(0,2).map((p)=>p[0].toUpperCase()).join("");return `<div class="founder-avatar flex items-center justify-center text-xs font-semibold text-white">${initials}</div>`;}function renderFounders(){foundersList.innerHTML=PAGE_DATA.founders.map((person)=>{return `<article class="rounded-2xl border border-white/15 bg-black/40 p-4"><div class="flex items-start gap-3">${founderAvatar(person)}<div><h3 class="founder-name text-base font-semibold text-white">${person.fullName}</h3><p class="founder-role mt-1 text-sm text-slate-200/85">${person.role}</p></div></div><div class="mt-4 grid grid-cols-1 gap-2 sm:grid-cols-3">${founderContactButton(PAGE_DATA.images.telegramIcon,"Telegram",person.contacts.telegram)}${founderContactButton(PAGE_DATA.images.vkIcon,"VK",person.contacts.vk)}${founderContactButton(PAGE_DATA.images.maxIcon,"MAX",person.contacts.max)}</div></article>`;}).join("");}let foundersRendered=false;let socialsRendered=false;function renderSocials(){socialsList.innerHTML=PAGE_DATA.socials.map((item,idx)=>{const disabled=item.isEnabled===false||isPlaceholder(item.href);const href=disabled?"javascript:void(0)":item.href;const soonLabel=PAGE_DATA.labels?.soon||"скоро";const rightHint=disabled?`<span class="text-white/70 text-xs">${soonLabel}</span>`:'<span class="text-white text-base">↗</span>';const delay=Math.min(idx*35,180);return `<li class="stagger-item" style="animation-delay:${delay}ms"><a href="${href}" target="_blank" rel="noreferrer" class="tap social-glass flex h-16 items-center justify-between rounded-2xl px-4 ${disabled?"disabled-link":""}"><span class="flex items-center gap-3">${socialIconImage(PAGE_DATA.images[item.iconKey],item.label)}<span class="social-brand-pill"><span class="social-text-strong">${brandLogoInline()}</span><span class="social-text-strong">в ${item.label}</span></span></span>${rightHint}</a></li>`;}).join("");}let lastActiveElement=null;function getFocusableElements(root){if(!root)return[];return Array.from(root.querySelectorAll('a[href],button:not([disabled]),textarea,input,select,[tabindex]:not([tabindex="-1"])',),).filter((el)=>!el.classList.contains("disabled-link")&&el.offsetParent!==null);}function focusFirstInModal(modal){const focusables=getFocusableElements(modal);if(focusables.length>0)focusables[0].focus();}function trapFocusInModal(event){if(event.key!=="Tab")return;const modal=document.querySelector(".modal-layer.open");if(!modal)return;const focusables=getFocusableElements(modal);if(focusables.length===0)return;const first=focusables[0];const last=focusables[focusables.length-1];if(event.shiftKey&&document.activeElement===first){event.preventDefault();last.focus();}else if(!event.shiftKey&&document.activeElement===last){event.preventDefault();first.focus();}}let lockedScrollY=0;function lockScroll(){lockedScrollY=window.scrollY||window.pageYOffset||0;document.body.style.position="fixed";document.body.style.top=`-${lockedScrollY}px`;document.body.style.left="0";document.body.style.right="0";document.body.style.width="100%";}function unlockScroll(){document.body.style.position="";document.body.style.top="";document.body.style.left="";document.body.style.right="";document.body.style.width="";window.scrollTo(0,lockedScrollY);}function openModal(id){const m=document.getElementById(id);if(!m)return;lastActiveElement=document.activeElement;const card=m.querySelector("[data-modal-card]");if(card){card.style.transform="";card.style.transition="";}m.setAttribute("aria-hidden","false");m.classList.add("open");document.body.classList.add("overflow-hidden");lockScroll();if(id==="contactsModal")ensureImageLoaded(contactsBackdrop,PAGE_DATA.images.backdrop);if(id==="socialsModal")ensureImageLoaded(socialsBackdrop,PAGE_DATA.images.backdrop);if(id==="contactsModal"&&!foundersRendered){renderFounders();foundersRendered=true;}if(id==="socialsModal"&&!socialsRendered){renderSocials();socialsRendered=true;}focusFirstInModal(m);}function closeModal(id){const m=document.getElementById(id);if(!m)return;const card=m.querySelector("[data-modal-card]");if(card&&m.classList.contains("open")){card.classList.add("is-closing");setTimeout(()=>{card.classList.remove("is-closing");card.style.transform="";card.style.transition="";},260);}m.classList.remove("open");m.setAttribute("aria-hidden","true");if(card){card.style.transform="";card.style.transition="";}if(!document.querySelector(".modal-layer.open")){document.body.classList.remove("overflow-hidden");unlockScroll();if(lastActiveElement&&typeof lastActiveElement.focus==="function")lastActiveElement.focus();lastActiveElement=null;}}function setActiveGlow(btn){[openContactsButton,openSocialsButton].forEach((b)=>b&&b.classList.remove("premium-btn-active"));btn.classList.add("premium-btn-active");setTimeout(()=>btn.classList.remove("premium-btn-active"),950);}function bindSwipeClose(modalId,selector){const modal=document.getElementById(modalId);const card=modal?.querySelector(selector);const scroller=card?.querySelector(".modal-scroll");if(!modal||!card)return;let startY=0;let dragging=false;let deltaY=0;let allowDrag=false;card.addEventListener("touchstart",(e)=>{if(e.touches.length!==1)return;allowDrag=!scroller||scroller.scrollTop<=0;if(!allowDrag)return;startY=e.touches[0].clientY;dragging=true;deltaY=0;card.style.transition="none";},{passive:true});card.addEventListener("touchmove",(e)=>{if(!dragging||!allowDrag)return;deltaY=Math.max(0,e.touches[0].clientY-startY);if(deltaY>0)card.style.transform=`translateY(${Math.min(deltaY,220)}px)scale(${1-Math.min(deltaY,220)/2200})`;},{passive:true});card.addEventListener("touchend",()=>{if(!dragging)return;dragging=false;card.style.transition="transform .34s var(--tap-spring),opacity .24s ease";if(deltaY>120){closeModal(modalId);}else{card.style.transform="";}allowDrag=false;});card.addEventListener("touchcancel",()=>{dragging=false;allowDrag=false;card.style.transform="";card.style.transition="";});}function bindEvents(){openContactsButton?.addEventListener("click",()=>{setActiveGlow(openContactsButton);openModal("contactsModal");});openSocialsButton?.addEventListener("click",()=>{setActiveGlow(openSocialsButton);openModal("socialsModal");});document.querySelectorAll("[data-close]").forEach((el)=>{el.addEventListener("click",()=>{const t=el.getAttribute("data-close");if(t==="contacts")closeModal("contactsModal");if(t==="socials")closeModal("socialsModal");});});document.addEventListener("keydown",(e)=>{if(e.key==="Escape"){closeModal("contactsModal");closeModal("socialsModal");}trapFocusInModal(e);});bindSwipeClose("contactsModal","[data-modal-card='contacts']");bindSwipeClose("socialsModal","[data-modal-card='socials']");window.addEventListener("resize",()=>{setResponsiveProfile();updateHeroOverlayContrast();});}function init(){preloadImage(PAGE_DATA.images.backdrop);preloadImages([PAGE_DATA.images.telegramIcon,PAGE_DATA.images.vkIcon,PAGE_DATA.images.maxIcon,PAGE_DATA.images.brandLogo,]);ensureImageLoaded(heroBackdrop,PAGE_DATA.images.backdrop);ensureImageLoaded(heroBackdropBlur,PAGE_DATA.images.backdrop);commonEmail.textContent=PAGE_DATA.commonContacts.email;commonEmail.href=`mailto:${PAGE_DATA.commonContacts.email}`;commonAddress.textContent=PAGE_DATA.commonContacts.address;legalCompany.textContent=PAGE_DATA.legal.company;legalInn.textContent=PAGE_DATA.legal.inn;applyTextLabels();bindLongPressCopy(commonEmail,()=>PAGE_DATA.commonContacts.email);bindLongPressCopy(commonAddress,()=>PAGE_DATA.commonContacts.address);setResponsiveProfile();updateHeroOverlayContrast();bindEvents();}init();